function lonelyNumbers(nums) {
    let numSet = new Set(nums);
    let lonely = [];
    for (let num of nums) {
        if (!numSet.has(num - 1) && !numSet.has(num + 1)) {
            lonely.push(num);
        }
    }
    return lonely;
}
```


    1. Create a set `num_set` containing all the unique numbers in the given array `nums`.
2. Create an empty list or vector `lonely` to store the lonely numbers.
3. Iterate through the numbers in `nums`.
4. For each number `num`, check if `num - 1` and `num + 1` do not exist in the set `num_set`.
5. If both conditions are satisfied, the number is lonely, and we append it to our `lonely` list or vector.
6. Return the `lonely` list or vector containing all the lonely numbers.

