import java.util.HashSet;
import java.util.ArrayList;

public ArrayList<Integer> lonelyNumbers(int[] nums) {
    HashSet<Integer> num_set = new HashSet<>();
    for (int num : nums) {
        num_set.add(num);
    }
    ArrayList<Integer> lonely = new ArrayList<>();
    for (int num : nums) {
        if (!num_set.contains(num - 1) && !num_set.contains(num + 1)) {
            lonely.add(num);
        }
    }
    return lonely;
}
```


